@Transactional
open fun getCurrentVulnerabilitiesOptimized(
    accessibleAssetIds: Set<Long>,
    isAdmin: Boolean,
    severity: String?,
    system: String?,
    exceptionStatus: String?,
    product: String?,
    adDomain: String?,
    cloudAccountId: String? = null,
    page: Int,
    size: Int,
    sort: String? = null,
    sortDir: String? = null,
    knownTotal: Long? = null
): com.secman.dto.PaginatedVulnerabilitiesResponse {
    log.debug("Getting current vulnerabilities (optimized) - isAdmin: {}, assetIds: {}, severity: {}, system: {}, exceptionStatus: {}, cloudAccountId: {}, page: {}, size: {}",
        isAdmin, if (isAdmin) "ALL" else accessibleAssetIds.size, severity, system, exceptionStatus, cloudAccountId, page, size)

    // Pre-process filter values: lowercase domain filter since adDomain is stored normalized
    val normalizedDomainFilter = adDomain?.takeIf { it.isNotBlank() }?.lowercase()
    val normalizedCloudAccountIdFilter = cloudAccountId?.takeIf { it.isNotBlank() }
    val normalizedSeverity = severity?.takeIf { it.isNotBlank() }
    val normalizedSystem = system?.takeIf { it.isNotBlank() }
    val normalizedProduct = product?.takeIf { it.isNotBlank() }
    val normalizedExceptionStatus = exceptionStatus?.lowercase()?.replace("-", "_")?.takeIf { it.isNotBlank() }

    // Non-ADMIN: check for empty accessible assets
    if (!isAdmin && accessibleAssetIds.isEmpty()) {
        return com.secman.dto.PaginatedVulnerabilitiesResponse(
            content = emptyList(),
            totalElements = 0,
            totalPages = 0,
            currentPage = page,
            pageSize = size,
            hasNext = false,
            hasPrevious = false
        )
    }

    // Get active exceptions ONCE (cached)
    val activeExceptions = getActiveExceptions()
    log.debug("Found {} active exceptions (from cache)", activeExceptions.size)

    // PERFORMANCE (Feature 073): When exception status filter is set,
    // use SQL-level filtering to avoid loading all 358k rows into memory
    // This now applies to both admin AND non-admin users
    if (!normalizedExceptionStatus.isNullOrBlank()) {
        return if (isAdmin) {
            getCurrentVulnerabilitiesByStatusSql(
                normalizedExceptionStatus, normalizedSeverity, normalizedSystem,
                normalizedProduct, normalizedDomainFilter, normalizedCloudAccountIdFilter,
                activeExceptions, page, size, knownTotal, sort, sortDir
            )
        } else {
            // Feature 073: SQL-level filtering for non-admin users
            getCurrentVulnerabilitiesByStatusSqlWithAccessControl(
                accessibleAssetIds, normalizedExceptionStatus, normalizedSeverity,
                normalizedSystem, normalizedProduct, normalizedDomainFilter,
                normalizedCloudAccountIdFilter, activeExceptions, page, size, knownTotal,
                sort, sortDir
            )
        }
    }

    // Determine if custom sort is requested
    val hasCustomSort = !sort.isNullOrBlank() && SORT_FIELD_MAP.containsKey(sort)
    val pageable = io.micronaut.data.model.Pageable.from(page, size)

    // PERFORMANCE: Use EntityManager with dynamic ORDER BY for custom sorts.
    // The @Query JPQL methods have hardcoded ORDER BY, so Pageable.sort doesn't work with them.
    // Non-admin users now reach this branch too (Phase 2 of the sort fix); accessible-asset
    // filtering is applied inside the helper when accessibleAssetIds is non-null.
    if (hasCustomSort) {
        return getCurrentVulnerabilitiesWithCustomSort(
            normalizedSeverity, normalizedSystem, normalizedProduct,
            normalizedDomainFilter, normalizedCloudAccountIdFilter,
            normalizedExceptionStatus, activeExceptions,
            sort, sortDir, page, size,
            accessibleAssetIds = if (isAdmin) null else accessibleAssetIds
        )
    }

    // Choose query based on admin status (uses default ORDER BY from JPQL)
    // No exception status filter at this point - use standard pagination
    val vulnPage = if (isAdmin) {
        vulnerabilityRepository.findLatestVulnerabilitiesPerAssetWithFilters(
            severity = normalizedSeverity,
            assetName = normalizedSystem,
            productFilter = normalizedProduct,
            domainFilter = normalizedDomainFilter,
            cloudAccountIdFilter = normalizedCloudAccountIdFilter,
            pageable = pageable
        )
    } else {
        vulnerabilityRepository.findLatestVulnerabilitiesWithAccessControl(
            accessibleAssetIds = accessibleAssetIds,
            severity = normalizedSeverity,
            assetName = normalizedSystem,
            productFilter = normalizedProduct,
            domainFilter = normalizedDomainFilter,
            cloudAccountIdFilter = normalizedCloudAccountIdFilter,
            pageable = pageable
        )
    }

    val currentVulns = vulnPage.content
    log.debug("Found {} vulnerabilities from database query", currentVulns.size)

    // Map to DTOs with exception information
    val vulnsWithException = mapToVulnerabilityDtos(currentVulns, activeExceptions)

    // Check if all filters are empty (for cached count optimization)
    val hasNoFilters = normalizedSeverity == null && normalizedSystem == null && normalizedProduct == null
            && normalizedDomainFilter == null && normalizedCloudAccountIdFilter == null

    // No exception filter - use DB pagination metadata
    // PERFORMANCE: Use cached total count for unfiltered admin queries, or knownTotal if provided
    val totalElements = knownTotal ?: if (isAdmin && hasNoFilters) {
        getCachedTotalCount()
    } else {
        vulnPage.totalSize
    }
    val totalPages = if (totalElements > 0) kotlin.math.ceil(totalElements.toDouble() / size).toInt() else 0

    val filteredResult = com.secman.dto.PaginatedVulnerabilitiesResponse(
        content = vulnsWithException,
        totalElements = totalElements,
        totalPages = totalPages,
        currentPage = page,
        pageSize = size,
        hasNext = page < totalPages - 1,
        hasPrevious = page > 0
    )

    log.info("Returning {} current vulnerabilities (page {}/{}, total {})",
        filteredResult.content.size, page + 1, filteredResult.totalPages, filteredResult.totalElements)
    return filteredResult
}

/**
 * SQL-level exception status filtering for admin users
 * Eliminates loading all 358k rows into memory when filtering by overdue/excepted/ok
 */
private fun getCurrentVulnerabilitiesByStatusSql(
    exceptionStatus: String,
    severity: String?,
    system: String?,
    product: String?,
    domainFilter: String?,
    cloudAccountIdFilter: String?,
    activeExceptions: List<VulnerabilityException>,
    page: Int,
    size: Int,
    knownTotal: Long? = null,
    sort: String? = null,
    sortDir: String? = null
): com.secman.dto.PaginatedVulnerabilitiesResponse {
    val reminderOneDays = vulnerabilityConfigService.getReminderOneDays()
    val thresholdDate = LocalDateTime.now().minusDays(reminderOneDays.toLong())
    val pageOffset = page * size

    // Check if all additional filters are empty (for cached count optimization)
    val hasNoAdditionalFilters = severity == null && system == null && product == null
            && domainFilter == null && cloudAccountIdFilter == null

    // When the user has chosen a sort column, route through the dynamic-SQL helper
    // so ORDER BY is honored. Default-sort requests stay on the existing tuned
    // @Query repository methods to preserve their performance characteristics.
    val hasCustomSort = !sort.isNullOrBlank() && SORT_FIELD_MAP_NATIVE.containsKey(sort)

    log.debug("Using SQL-level exception status filter: {} (threshold: {} days, date: {}, skipCount: {}, hasNoAdditionalFilters: {}, customSort: {})",
        exceptionStatus, reminderOneDays, thresholdDate, knownTotal != null, hasNoAdditionalFilters, hasCustomSort)

    if (hasCustomSort) {
        val (vulns, totalCount) = executeStatusFilteredCustomSortQuery(
            statusType = exceptionStatus,
            accessibleAssetIds = null,
            thresholdDate = thresholdDate,
            severity = severity,
            system = system,
            product = product,
            domainFilter = domainFilter,
            cloudAccountIdFilter = cloudAccountIdFilter,
            sort = sort,
            sortDir = sortDir,
            page = page,
            size = size
        )
        val effectiveTotal = knownTotal ?: totalCount
        val totalPages = if (effectiveTotal > 0) kotlin.math.ceil(effectiveTotal.toDouble() / size).toInt() else 0
        return com.secman.dto.PaginatedVulnerabilitiesResponse(
            content = mapToVulnerabilityDtos(vulns, activeExceptions),
            totalElements = effectiveTotal,
            totalPages = totalPages,
            currentPage = page,
            pageSize = size,
            hasNext = page < totalPages - 1,

/**
 * Map vulnerability entities to DTOs with exception and overdue status information
 */
private fun mapToVulnerabilityDtos(
    vulns: List<Vulnerability>,
    activeExceptions: List<VulnerabilityException>
): List<VulnerabilityWithExceptionDto> {
    return vulns.map { vuln ->
        val overdueInfo = calculateOverdueStatus(vuln, vuln.asset, activeExceptions)
        val matchingException = activeExceptions.firstOrNull { it.matches(vuln, vuln.asset) }

        VulnerabilityWithExceptionDto(
            id = vuln.id,
            asset = vuln.asset,
            assetId = vuln.asset.id!!,
            assetName = vuln.asset.name,
            assetIp = vuln.asset.ip,
            cloudInstanceId = vuln.asset.cloudInstanceId,
            vulnerabilityId = vuln.vulnerabilityId,
            cvssSeverity = vuln.cvssSeverity,
            vulnerableProductVersions = vuln.vulnerableProductVersions,
            daysOpen = vuln.daysOpen,
            scanTimestamp = vuln.scanTimestamp,
            hasException = matchingException != null,
            exceptionReason = matchingException?.reason,
            ageInDays = overdueInfo.ageInDays,
            overdueStatus = overdueInfo.status,
            daysOverdue = overdueInfo.daysOverdue,
            exceptionId = overdueInfo.exceptionId,
            exceptionEndDate = overdueInfo.exceptionEndDate,
            exceptionSubject = matchingException?.subject,
            exceptionScope = matchingException?.scope,
            exceptionScopesAsset = matchingException?.let { isAssetScoped(it) }
        )
    }
}

/**
 * True when the given exception covers one specific asset, false when its
 * scope spans multiple assets. Used by the UI to phrase scope hints.
 */
private fun isAssetScoped(exception: VulnerabilityException): Boolean {
    return when (exception.scope) {
        VulnerabilityException.Scope.IP -> true
        VulnerabilityException.Scope.ASSET -> true
        VulnerabilityException.Scope.GLOBAL -> false
        VulnerabilityException.Scope.AWS_ACCOUNT -> false
    }
}

/**
 * Execute paginated vulnerability query with custom ORDER BY using EntityManager
 * Required because Micronaut Data @Query with JPQL doesn't support dynamic Sort from Pageable
 */
private fun getCurrentVulnerabilitiesWithCustomSort(
    severity: String?,
    system: String?,
    product: String?,
    domainFilter: String?,
    cloudAccountIdFilter: String?,
    exceptionStatus: String?,
    activeExceptions: List<VulnerabilityException>,
    sort: String,
    sortDir: String?,
    page: Int,
    size: Int,
    accessibleAssetIds: Set<Long>? = null
): com.secman.dto.PaginatedVulnerabilitiesResponse {
    // SECURITY: Lock the access-control invariant. The non-admin path of
    // getCurrentVulnerabilitiesOptimized short-circuits empty asset sets before reaching
    // here; if a future refactor breaks that, fail fast with a clear message rather
    // than letting Hibernate emit a parser error for "IN ()".
    require(accessibleAssetIds == null || accessibleAssetIds.isNotEmpty()) {
        "Non-admin custom-sort path requires non-empty accessibleAssetIds"
    }

    // SECURITY: Only allow whitelisted sort columns to prevent SQL injection.
    // The SORT_FIELD_MAP values are compile-time constants, never user input.
    val sortColumn = SORT_FIELD_MAP[sort]
        ?: throw IllegalArgumentException("Invalid sort field: $sort. Allowed: ${SORT_FIELD_MAP.keys}")
    val direction = if (sortDir?.lowercase() == "asc") "ASC" else "DESC"

    log.debug("Custom sort query: ORDER BY {} {} (access-control: {})",
        sortColumn, direction, accessibleAssetIds?.size ?: "ADMIN")

    // Build JPQL dynamically with custom ORDER BY
    val jpqlBase = StringBuilder("""
        SELECT v FROM Vulnerability v
        JOIN FETCH v.asset a
        WHERE 1=1
    """.trimIndent())

    val countBase = StringBuilder("""
        SELECT COUNT(v) FROM Vulnerability v JOIN v.asset a
        WHERE 1=1
    """.trimIndent())

    val params = mutableMapOf<String, Any>()

    if (accessibleAssetIds != null) {
        // Non-admin path: restrict to assets the caller can see.
        // Empty set is filtered out by the early-return at the top of
        // getCurrentVulnerabilitiesOptimized, so :accessibleAssetIds is always non-empty here.
        jpqlBase.append(" AND a.id IN :accessibleAssetIds")
        countBase.append(" AND a.id IN :accessibleAssetIds")
        params["accessibleAssetIds"] = accessibleAssetIds
    }

    if (severity != null) {
        jpqlBase.append(" AND v.cvssSeverity = :severity")
        countBase.append(" AND v.cvssSeverity = :severity")
        params["severity"] = severity
    }
    if (system != null) {
        jpqlBase.append(" AND LOWER(a.name) LIKE LOWER(CONCAT('%', :assetName, '%'))")
        countBase.append(" AND LOWER(a.name) LIKE LOWER(CONCAT('%', :assetName, '%'))")
        params["assetName"] = system
    }
    if (product != null) {
        jpqlBase.append(" AND LOWER(v.vulnerableProductVersions) LIKE LOWER(CONCAT('%', :productFilter, '%'))")
        countBase.append(" AND LOWER(v.vulnerableProductVersions) LIKE LOWER(CONCAT('%', :productFilter, '%'))")
        params["productFilter"] = product
    }
    if (domainFilter != null) {
        jpqlBase.append(" AND a.adDomain LIKE CONCAT('%', :domainFilter, '%')")
        countBase.append(" AND a.adDomain LIKE CONCAT('%', :domainFilter, '%')")
        params["domainFilter"] = domainFilter
    }
    if (cloudAccountIdFilter != null) {
        jpqlBase.append(" AND a.cloudAccountId LIKE CONCAT('%', :cloudAccountIdFilter, '%')")
        countBase.append(" AND a.cloudAccountId LIKE CONCAT('%', :cloudAccountIdFilter, '%')")
        params["cloudAccountIdFilter"] = cloudAccountIdFilter
    }

    jpqlBase.append(" ORDER BY $sortColumn $direction")

    // Execute count query
    val countQuery = entityManager.createQuery(countBase.toString(), Long::class.javaObjectType)
    params.forEach { (k, v) -> countQuery.setParameter(k, v) }
    val totalCount = countQuery.singleResult

    // Execute data query with pagination
    val dataQuery = entityManager.createQuery(jpqlBase.toString(), Vulnerability::class.java)
    params.forEach { (k, v) -> dataQuery.setParameter(k, v) }
    dataQuery.firstResult = page * size
    dataQuery.maxResults = size

    @Suppress("UNCHECKED_CAST")
    val vulns = dataQuery.resultList as List<Vulnerability>

    val vulnsWithException = mapToVulnerabilityDtos(vulns, activeExceptions)
    val totalPages = if (totalCount > 0) kotlin.math.ceil(totalCount.toDouble() / size).toInt() else 0

    log.info("Custom sort query returned {} vulns (total: {}, sort: {} {})",
        vulns.size, totalCount, sortColumn, direction)

    return com.secman.dto.PaginatedVulnerabilitiesResponse(
        content = vulnsWithException,
        totalElements = totalCount,
        totalPages = totalPages,
        currentPage = page,
        pageSize = size,
        hasNext = page < totalPages - 1,
        hasPrevious = page > 0
    )
}

/**
 * Run a native-SQL paginated query for the four exception-status filter modes
 * (overdue / excepted / ok / not_excepted) with a user-chosen ORDER BY.
 *
 * Reused by both admin and non-admin code paths: pass null `accessibleAssetIds`
 * for admin (no asset restriction) or a non-empty set for access-controlled users.
 *
 * SECURITY: `sort` is looked up in [SORT_FIELD_MAP_NATIVE] before any string
 * concatenation, so user input never reaches the SQL ORDER BY clause directly.
 * All filter values are bound as parameters.
 */
private fun executeStatusFilteredCustomSortQuery(
    statusType: String,
    accessibleAssetIds: Set<Long>?,
    thresholdDate: LocalDateTime,
    severity: String?,
    system: String?,
    product: String?,
    domainFilter: String?,
    cloudAccountIdFilter: String?,
    sort: String,
    sortDir: String?,
    page: Int,
    size: Int
): Pair<List<Vulnerability>, Long> {
    // SECURITY: Lock the access-control invariant — see getCurrentVulnerabilitiesWithCustomSort
    // for rationale. Empty asset sets are the responsibility of the dispatcher to short-circuit;
    // we fail fast here if that ever drifts.
    require(accessibleAssetIds == null || accessibleAssetIds.isNotEmpty()) {
        "Non-admin status-filtered custom-sort path requires non-empty accessibleAssetIds"
    }

package com.secman.domain

import com.fasterxml.jackson.annotation.JsonIgnore
import io.micronaut.serde.annotation.Serdeable
import jakarta.persistence.*
import jakarta.validation.constraints.NotNull
import java.time.LocalDateTime

/**
 * Vulnerability entity representing a security vulnerability discovered during a scan.
 *
 * Linked to an Asset entity via ManyToOne relationship.
 * Feature 048: Uses transactional replace pattern - each import deletes existing vulnerabilities
 * for an asset and inserts current ones, ensuring only the latest state is stored.
 *
 * Related to: Feature 003-i-want-to (Vulnerability Management System)
 * Related to: Feature 048-prevent-duplicate-vulnerabilities
 *
 * @property id Unique identifier
 * @property asset Asset this vulnerability affects (required)
 * @property vulnerabilityId CVE or vulnerability identifier (e.g., "CVE-2016-2183")
 * @property cvssSeverity CVSS severity level (e.g., "High", "Critical", "Medium", "Low", "Informational")
 * @property vulnerableProductVersions Affected product/version information
 * @property daysOpen Text representation of days open (e.g., "58 days") - display only
 * @property scanTimestamp Discovery date (calculated from daysOpen for accurate overdue calculation)
 * @property importTimestamp When this data was imported (same for all vulns in batch, for "current" query)
 * @property patchPublicationDate When the vendor published the patch/fix (optional, from CrowdStrike API)
 * @property createdAt When the record was first created in the database (auto-generated)
 */
@Entity
@Table(
    name = "vulnerability",
    indexes = [
        Index(name = "idx_vulnerability_asset", columnList = "asset_id"),
        Index(name = "idx_vulnerability_asset_scan", columnList = "asset_id,scan_timestamp"),
        Index(name = "idx_vulnerability_severity", columnList = "cvss_severity"),
        // Query optimization indexes (Feature: Database Structure Optimization)
        Index(name = "idx_vulnerability_cve", columnList = "vulnerability_id"),                    // CVE ID lookups
        Index(name = "idx_vulnerability_asset_cve", columnList = "asset_id,vulnerability_id"),     // Duplicate detection
        Index(name = "idx_vulnerability_product", columnList = "vulnerable_product_versions"),     // Product filtering
        Index(name = "idx_vulnerability_scan_timestamp", columnList = "scan_timestamp"),           // Temporal queries
        Index(name = "idx_vulnerability_import_ts", columnList = "asset_id,import_timestamp"),      // "Current" queries
        Index(name = "idx_vulnerability_sort_order", columnList = "import_timestamp DESC, vulnerability_id")  // ORDER BY optimization for paginated queries
    ]
)
@Serdeable
data class Vulnerability(
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    var id: Long? = null,

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "asset_id", nullable = false)
    @JsonIgnore // Prevent lazy loading errors during JSON serialization
    @NotNull
    var asset: Asset,

    @Column(name = "vulnerability_id", length = 255)
    var vulnerabilityId: String? = null,

    @Column(name = "cvss_severity", length = 50)
    var cvssSeverity: String? = null,

    @Column(name = "vulnerable_product_versions", length = 512)
    var vulnerableProductVersions: String? = null,

    @Column(name = "days_open", length = 50)
    var daysOpen: String? = null,

    @Column(name = "scan_timestamp", nullable = false)
    @NotNull
    var scanTimestamp: LocalDateTime,

    @Column(name = "patch_publication_date")
    var patchPublicationDate: LocalDateTime? = null,

    @Column(name = "import_timestamp")
    var importTimestamp: LocalDateTime? = null,

    @Column(name = "created_at", updatable = false)
    var createdAt: LocalDateTime? = null
) {
    @PrePersist
    fun onCreate() {
        val now = LocalDateTime.now()
        createdAt = now
        // Default importTimestamp to createdAt if not explicitly set
        if (importTimestamp == null) {
            importTimestamp = now
        }
    }

    override fun toString(): String {
        return "Vulnerability(id=$id, vulnerabilityId='$vulnerabilityId', " +
                "cvssSeverity='$cvssSeverity', scanTimestamp=$scanTimestamp)"
    }

    override fun equals(other: Any?): Boolean {
        if (this === other) return true
        if (other !is Vulnerability) return false
        return id != null && id == other.id
    }

    override fun hashCode(): Int {
        return id?.hashCode() ?: 0
    }
}

