/**
 * Index of pre-parsed active exceptions, bucketed for cheap per-vulnerability
 * matching. Built once per page-render and reused for every row.
 *
 * Why this exists: the entity-level `VulnerabilityException.matches()` reparses
 * comma-separated CVE lists (`subjectValue.split(",").map{ it.trim() }`) on every
 * call. With 50 exceptions × 50 vulns per page, the parse cost dominates the page
 * render. Pre-parsing once and bucketing by Subject also lets us skip exceptions
 * that obviously cannot match (e.g., we never test PRODUCT exceptions when the
 * exception list is bucketed and the bucket is empty).
 *
 * Match priority mirrors entity logic:
 *   1. ALL_VULNS exceptions (subject always matches; fall through to scope check)
 *   2. PRODUCT exceptions (CVE-equality OR substring of vulnerableProductVersions)
 *   3. CVE exceptions (membership in pre-parsed CVE set)
 *
 * Scope match is always evaluated against the matched-subject candidates only.
 */
private class ExceptionMatchIndex(activeExceptions: List<VulnerabilityException>) {
    // Pre-parsed CVE-list exceptions: each entry is the original entity plus a
    // parsed Set<String> for O(1) membership testing.
    private data class CveBucket(val ex: VulnerabilityException, val cves: Set<String>)

    private val allVulns: List<VulnerabilityException>
    private val productExceptions: List<VulnerabilityException>
    private val cveBuckets: List<CveBucket>

    init {
        val a = mutableListOf<VulnerabilityException>()
        val p = mutableListOf<VulnerabilityException>()
        val c = mutableListOf<CveBucket>()
        for (ex in activeExceptions) {
            when (ex.subject) {
                VulnerabilityException.Subject.ALL_VULNS -> a += ex
                VulnerabilityException.Subject.PRODUCT -> p += ex
                VulnerabilityException.Subject.CVE -> {
                    val sv = ex.subjectValue
                    if (!sv.isNullOrBlank()) {
                        c += CveBucket(ex, sv.split(",").map { it.trim() }.toSet())
                    }
                }
            }
        }
        allVulns = a
        productExceptions = p
        cveBuckets = c
    }

    /**
     * Return the first active exception that matches this (vulnerability, asset)
     * pair, mirroring `VulnerabilityException.matches` semantics but without
     * re-parsing CVE lists on every call.
     */
    fun firstMatch(v: Vulnerability, a: Asset): VulnerabilityException? {
        allVulns.firstOrNull { scopeMatches(it, a) }?.let { return it }
        productExceptions.firstOrNull { productSubjectMatches(it, v) && scopeMatches(it, a) }?.let { return it }
        cveBuckets.firstOrNull { v.vulnerabilityId in it.cves && scopeMatches(it.ex, a) }?.let { return it.ex }
        return null
    }

    private fun productSubjectMatches(ex: VulnerabilityException, v: Vulnerability): Boolean {
        val sv = ex.subjectValue ?: return false
        return v.vulnerabilityId == sv ||
            v.vulnerableProductVersions?.contains(sv, ignoreCase = true) == true
    }

    private fun scopeMatches(ex: VulnerabilityException, a: Asset): Boolean = when (ex.scope) {
        VulnerabilityException.Scope.GLOBAL -> true
        VulnerabilityException.Scope.IP -> a.ip == ex.scopeValue
        VulnerabilityException.Scope.ASSET -> ex.assetId != null && ex.assetId == a.id
        VulnerabilityException.Scope.AWS_ACCOUNT -> a.cloudAccountId != null && a.cloudAccountId == ex.scopeValue
    }
}

