 * Get all filter dropdown options in a single response.
 *
 * Why this exists: the Current Vulnerabilities table loads three independent
 * dropdowns (products, AD domains, cloud account IDs) on every mount. Three
 * round trips, three SELECT DISTINCT scans of the vulnerability/asset tables.
 * This endpoint collapses them into one call. Filter options change only when
 * a CrowdStrike import lands, so a 60-second HTTP cache header is safe.
 *
 * Endpoint: GET /api/vulnerabilities/filter-options
 * Response: { products: [...], adDomains: [...], cloudAccountIds: [...] }
 */
@Serdeable
data class FilterOptionsResponse(
    val products: List<String>,
    val adDomains: List<String>,
    val cloudAccountIds: List<String>
)

@Get("/api/vulnerabilities/filter-options")
@Secured(SecurityRule.IS_AUTHENTICATED)
open fun getFilterOptions(
    @Nullable @QueryValue productSearch: String?,
    @Nullable @QueryValue productLimit: Int?
): HttpResponse<FilterOptionsResponse> {
    return try {
        val resultLimit = minOf(maxOf(productLimit ?: 50, 1), 1000)
        val response = FilterOptionsResponse(
            products = vulnerabilityService.getDistinctProducts(productSearch, resultLimit),
            adDomains = vulnerabilityService.getDistinctAdDomains(),
            cloudAccountIds = vulnerabilityService.getDistinctCloudAccountIds()
        )
        // Filter options only change at import time; allow shared HTTP caches
        // to reuse the response for 60s, with stale-while-revalidate as a
        // friendly fallback if a refresh races an import.
        HttpResponse.ok(response)
            .header("Cache-Control", "private, max-age=60, stale-while-revalidate=30")
    } catch (e: Exception) {
        log.error("Error fetching combined filter options", e)
        HttpResponse.serverError()
    }
}

